function solve(n, edges, label) {
    // Build adjacency list
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let maxLen = 1;

    // We'll use BFS with a state that tracks visited nodes and character counts
    // Since n is small (<=14), we can use a bitmask to represent visited nodes
    for (let start = 0; start < n; start++) {
        const queue = [];
        queue.push({
            node: start,
            visited: 1 << start,
            freq: new Array(26).fill(0),
            oddCount: 0
        });
        const startChar = label.charCodeAt(start) - 97;
        const initialFreq = new Array(26).fill(0);
        initialFreq[startChar] = 1;
        queue[0].freq = initialFreq;
        queue[0].oddCount = 1;

        while (queue.length > 0) {
            const current = queue.shift();
            const { node, visited, freq, oddCount } = current;

            // Check if current state can form a palindrome
            if (oddCount <= 1) {
                const currentLen = countChars(freq);
                if (currentLen > maxLen) {
                    maxLen = currentLen;
                }
            }

            // Explore neighbors
            for (const neighbor of adj[node]) {
                if (!(visited & (1 << neighbor))) {
                    const newVisited = visited | (1 << neighbor);
                    const neighborChar = label.charCodeAt(neighbor) - 97;
                    const newFreq = [...freq];
                    newFreq[neighborChar]++;
                    const newOddCount = updateOddCount(oddCount, neighborChar, newFreq[neighborChar]);
                    queue.push({
                        node: neighbor,
                        visited: newVisited,
                        freq: newFreq,
                        oddCount: newOddCount
                    });
                }
            }
        }
    }

    return maxLen;
}

function countChars(freq) {
    return freq.reduce((sum, count) => sum + count, 0);
}

function updateOddCount(oldOddCount, char, newCount) {
    const wasOdd = (newCount - 1) % 2 === 1;
    const isOdd = newCount % 2 === 1;
    if (wasOdd && !isOdd) {
        return oldOddCount - 1;
    } else if (!wasOdd && isOdd) {
        return oldOddCount + 1;
    }
    return oldOddCount;
}

