fun solve(n: Long, edges: Array<Array<Long>>, label: String): Long {
    val adj = Array(n.toInt()) { mutableListOf<Int>() }
    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        adj[u].add(v)
        adj[v].add(u)
    }

    var maxLen = 1L

    for (start in 0 until n.toInt()) {
        val queue = ArrayDeque<State>()
        val initialFreq = IntArray(26)
        val startChar = label[start] - 'a'
        initialFreq[startChar] = 1
        queue.add(State(start, 1 shl start, initialFreq, 1))

        while (queue.isNotEmpty()) {
            val current = queue.removeFirst()
            val (node, visited, freq, oddCount) = current

            if (oddCount <= 1) {
                val currentLen = freq.sum().toLong()
                if (currentLen > maxLen) {
                    maxLen = currentLen
                }
            }

            for (neighbor in adj[node]) {
                if ((visited and (1 shl neighbor)) == 0) {
                    val newVisited = visited or (1 shl neighbor)
                    val neighborChar = label[neighbor] - 'a'
                    val newFreq = freq.copyOf()
                    newFreq[neighborChar]++
                    val newOddCount = updateOddCount(oddCount, neighborChar, newFreq[neighborChar])
                    queue.add(State(neighbor, newVisited, newFreq, newOddCount))
                }
            }
        }
    }

    return maxLen
}

data class State(
    val node: Int,
    val visited: Int,
    val freq: IntArray,
    val oddCount: Int
) {
    override fun equals(other: Any?): Boolean {
        if (this === other) return true
        if (javaClass != other?.javaClass) return false

        other as State

        if (node != other.node) return false
        if (visited != other.visited) return false
        if (!freq.contentEquals(other.freq)) return false
        if (oddCount != other.oddCount) return false

        return true
    }

    override fun hashCode(): Int {
        var result = node
        result = 31 * result + visited
        result = 31 * result + freq.contentHashCode()
        result = 31 * result + oddCount
        return result
    }
}

fun updateOddCount(oldOddCount: Int, char: Int, newCount: Int): Int {
    val wasOdd = (newCount - 1) % 2 == 1
    val isOdd = newCount % 2 == 1
    return when {
        wasOdd && !isOdd -> oldOddCount - 1
        !wasOdd && isOdd -> oldOddCount + 1
        else -> oldOddCount
    }
}
